const config = {
  telegramBotToken: 'replace_me_telegram_bot_token',
  backendBaseUrl: 'https://replace_me_public_backend_url',
  botSourceChannel: 'telegram_bot',
  botDocumentKind: 'primary_document',
  createGoogleSheet: 'true',
  defaultOrganizationName: '',
  defaultPointName: '',
  maxDocumentPages: 12,
  pollIntervalSeconds: 5,
  pollMaxAttempts: 60,
};

const ui = {
  startText: [
    'АвтоСнаб Документы',
    '',
    'Отправьте фото, скан или PDF одного документа.',
    'Если у документа несколько страниц, отправляйте их по очереди.',
    'После последней страницы нажмите «Продолжить».',
  ].join('\n'),
  collectingText: 'Будут ещё страницы этого документа? Если да, отправьте следующую страницу. Если нет, нажмите «Продолжить».',
  processingText: 'Документ отправлен в backend. Обработка уже началась. Когда результат будет готов, я пришлю его сюда автоматически.',
  resetText: 'Черновик документа очищен. Отправьте новый файл, чтобы начать заново.',
  unknownText: 'Отправьте фото, скан или PDF документа. После последней страницы нажмите «Продолжить».',
};

const replyKeyboard = JSON.stringify({
  keyboard: [
    [{ text: 'Продолжить' }, { text: 'Статус' }],
    [{ text: 'Новый документ' }, { text: 'Сбросить' }],
  ],
  resize_keyboard: true,
  is_persistent: true,
  input_field_placeholder: 'Отправьте файл или выберите действие',
});

return [{ json: { ...$json, config, ui, replyKeyboard } }];

const msg = $json.message || {};
const text = String(msg.text || '').trim();
const normalizedText = text.toLowerCase();
const chatId = msg.chat?.id ? String(msg.chat.id) : null;
const userId = msg.from?.id ? String(msg.from.id) : null;
const username = msg.from?.username || [msg.from?.first_name, msg.from?.last_name].filter(Boolean).join(' ') || null;
const photo = Array.isArray(msg.photo) && msg.photo.length ? msg.photo[msg.photo.length - 1] : null;
const document = msg.document || null;
const fileId = document?.file_id || photo?.file_id || null;
const fileName = document?.file_name || (photo ? `telegram-photo-${photo.file_unique_id || Date.now()}.jpg` : null);
const mimeType = document?.mime_type || (photo ? 'image/jpeg' : null);

let intent = 'unknown';
if (['/start', '/menu', '/help', 'новый документ', 'новый'].includes(normalizedText)) intent = 'start_session';
else if (normalizedText === 'продолжить') intent = 'finalize';
else if (normalizedText === 'статус' || normalizedText === '/status') intent = 'status';
else if (normalizedText === 'сбросить' || normalizedText === '/reset') intent = 'reset';
else if (fileId) intent = 'append_file';

return [{
  json: {
    ...$json,
    intent,
    text,
    normalizedText,
    chatId,
    userId,
    username,
    fileId,
    fileName,
    mimeType,
  }
}];

const config = $json.config || {};
if (!$json.chatId) {
  return [{ json: { ...$json, appendError: 'Не найден chatId для текущего сообщения.' } }];
}
if (!$json.fileId) {
  return [{ json: { ...$json, appendError: 'Telegram не передал файл в сообщении.' } }];
}
const sessionRow = $json.data?.[0] || null;
const shouldResetSession = !sessionRow || sessionRow.status !== 'collecting';
const sessionFilesJson = shouldResetSession ? '[]' : (sessionRow.files_json || '[]');
const organizationName = sessionRow?.organization_name || config.defaultOrganizationName || '';
const pointName = sessionRow?.point_name || config.defaultPointName || '';
return [{ json: { ...$json, sessionRowId: sessionRow?.id || '', sessionFilesJson, organizationName, pointName, sessionAutoOpened: shouldResetSession } }];

const response = $json.body ? $json : { statusCode: 200, body: $json };
const body = response.body || {};
const result = body.result || {};
const source = $('Prepare File Download').first().json;
if (Number(response.statusCode || 200) >= 400 || !result.file_path) {
  const detail = body.description || body.message || 'Telegram не вернул путь к файлу.';
  return [{ json: { ...source, downloadError: detail } }];
}
return [{ json: { ...source, telegramFilePath: result.file_path } }];

const inputItem = $input.first();
const binaryMap = inputItem?.binary || {};
const binary = binaryMap.uploadedFile || binaryMap.data || Object.values(binaryMap)[0] || null;
if (!binary?.data) {
  return [{ json: { ...$json, storeError: 'Не удалось получить бинарные данные файла из Telegram.' } }];
}
let files = [];
try {
  const parsed = JSON.parse($json.sessionFilesJson || '[]');
  files = Array.isArray(parsed) ? parsed : [];
} catch {
  return [{ json: { ...$json, storeError: 'Не удалось прочитать сохранённые страницы документа.' } }];
}
const maxPages = Number($json.config?.maxDocumentPages || 12);
if (files.length >= maxPages) {
  return [{ json: { ...$json, storeError: `В одном документе сейчас можно отправить не больше ${maxPages} страниц.` } }];
}
files.push({
  fileId: $json.fileId,
  fileName: $json.fileName || binary.fileName || `page-${files.length + 1}`,
  mimeType: binary.mimeType || $json.mimeType || 'application/octet-stream',
  data: binary.data,
  addedAt: new Date().toISOString(),
});
return [{
  json: {
    ...$json,
    filesCount: files.length,
    filesJson: JSON.stringify(files),
    statusToPersist: 'collecting',
    backendUploadId: '',
    backendTraceId: '',
  }
}];

const session = $json.data?.[0] || null;
const config = $json.config || {};
if (!session?.id) {
  return [{ json: { ...$json, finalizeError: 'Нет активного документа. Сначала отправьте фото, скан или PDF.' } }];
}
let files = [];
try {
  const parsed = JSON.parse(session.files_json || '[]');
  files = Array.isArray(parsed) ? parsed : [];
} catch {
  return [{ json: { ...$json, finalizeError: 'Не удалось прочитать сохранённые страницы документа.' } }];
}
if (!files.length) {
  return [{ json: { ...$json, finalizeError: 'Документ пока пустой. Сначала отправьте хотя бы одну страницу.' } }];
}
const maxPages = Number(config.maxDocumentPages || 12);
if (files.length > maxPages) {
  return [{ json: { ...$json, finalizeError: `Сейчас backend принимает не больше ${maxPages} страниц в одном документе.` } }];
}
const uploadContract = {
  source_channel: config.botSourceChannel || 'telegram_bot',
  document_kind: config.botDocumentKind || 'primary_document',
  source_user_id: $json.userId || session.user_id,
  source_username: $json.username || session.username || null,
  source_chat_id: $json.chatId || session.chat_id,
  organization_name: session.organization_name || config.defaultOrganizationName || null,
  point_name: session.point_name || config.defaultPointName || null,
  create_google_sheet: String(config.createGoogleSheet || 'true'),
};
const binary = {};
files.forEach((file, index) => {
  binary[`file_${index + 1}`] = {
    data: file.data,
    mimeType: file.mimeType || 'application/octet-stream',
    fileName: file.fileName || `page-${index + 1}`,
  };
});
return [{ json: { ...$json, sessionRowId: session.id, uploadContract, filesCount: files.length, filesJsonSource: session.files_json || '[]' }, binary }];

const source = $('Prepare Finalize').first().json;
const response = $json.body ? $json : { statusCode: 200, body: $json };
const body = response.body || {};
const statusCode = Number(response.statusCode || 200);
const detail = body.detail;
let uploadError = null;
if (statusCode >= 400) {
  if (typeof detail === 'string') uploadError = detail;
  else if (detail && typeof detail === 'object') uploadError = detail.error_message || JSON.stringify(detail);
  else uploadError = body.message || `Backend вернул ошибку ${statusCode}.`;
} else if ((body.status || '') !== 'accepted_for_processing') {
  uploadError = body.unsupported_reason || body.message || 'Backend не принял документ в обработку.';
}
const uploadAccepted = !uploadError && Boolean(body.upload_id);
const replyText = uploadAccepted
  ? source.ui.processingText
  : `Не удалось передать документ в backend.\n${uploadError || 'Неизвестная ошибка.'}`;
return [{
  json: {
    ...source,
    uploadAccepted,
    uploadError,
    replyText,
    backendUploadId: body.upload_id || '',
    backendTraceId: body.trace_id || '',
    backendStatus: body.status || '',
    statusToPersist: uploadAccepted ? 'processing' : 'collecting',
    filesJsonToPersist: uploadAccepted ? '[]' : (source.filesJsonSource || '[]'),
  }
}];

function formatMoney(value) {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  if (!Number.isFinite(num)) return String(value);
  return num.toLocaleString('ru-RU', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
}

function buildFinalText(body) {
  const lines = [];
  const summary = body.document_summary || {};
  if (body.status === 'processing_error') {
    lines.push('Не удалось обработать документ.');
    if (body.error_text) lines.push(body.error_text);
    return lines.join('\n');
  }
  if (body.google_spreadsheet_error && !body.google_spreadsheet_url) {
    lines.push('Документ распознан, но не удалось записать результат в Google Таблицы.');
    lines.push(body.google_spreadsheet_error);
    return lines.join('\n');
  }
  if (body.status === 'possible_duplicate') {
    lines.push('Документ обработан, но похож на дубль.');
  } else if (body.status === 'requires_review') {
    lines.push('Документ обработан и требует проверки.');
  } else {
    lines.push('Документ готов.');
  }
  const summaryLines = [];
  if (summary.supplier) summaryLines.push(`Поставщик: ${summary.supplier}`);
  if (summary.invoice_number) {
    const datePart = summary.invoice_date ? ` от ${summary.invoice_date}` : '';
    summaryLines.push(`Накладная: ${summary.invoice_number}${datePart}`);
  } else if (summary.invoice_date) {
    summaryLines.push(`Дата документа: ${summary.invoice_date}`);
  }
  if (summary.document_form) summaryLines.push(`Форма: ${summary.document_form}`);
  if (summary.items_count) summaryLines.push(`Строк распознано: ${summary.items_count}`);
  if (summary.total_sum !== null && summary.total_sum !== undefined) summaryLines.push(`Сумма: ${formatMoney(summary.total_sum)}`);
  if (summary.duplicate_indicator && ['Да', '?'].includes(String(summary.duplicate_indicator))) {
    summaryLines.push(`Признак дубля: ${summary.duplicate_indicator}`);
  }
  if (summaryLines.length) {
    lines.push('');
    lines.push(...summaryLines);
  }
  if (body.google_spreadsheet_url) {
    lines.push('');
    lines.push('Готовая таблица:');
    lines.push(body.google_spreadsheet_url);
  }
  if (body.google_spreadsheet_error && body.google_spreadsheet_url) {
    lines.push('');
    lines.push(`Предупреждение: ${body.google_spreadsheet_error}`);
  }
  return lines.join('\n');
}

const state = $('Wait Before Poll').first().json;
const response = $json.body ? $json : { statusCode: 200, body: $json };
const body = response.body || {};
const statusCode = Number(response.statusCode || 200);
if (statusCode >= 400) {
  const detail = body.detail;
  const errorText = typeof detail === 'string' ? detail : (detail?.error_message || body.message || `Backend вернул ошибку ${statusCode}.`);
  return [{ json: { ...state, pollCompleted: true, backendFinalStatus: 'processing_error', finalReplyText: `Не удалось получить итоговый статус документа.\n${errorText}`, googleSpreadsheetUrl: null, googleSpreadsheetError: errorText } }];
}
if (!body.completed) {
  const nextAttempt = Number(state.pollAttempt || 1) + 1;
  const maxAttempts = Number(state.config?.pollMaxAttempts || 60);
  return [{ json: { ...state, pollCompleted: false, pollAttempt: nextAttempt, shouldStopPolling: nextAttempt > maxAttempts } }];
}
return [{
  json: {
    ...state,
    pollCompleted: true,
    backendFinalStatus: body.status || 'processed',
    finalReplyText: buildFinalText(body),
    googleSpreadsheetUrl: body.google_spreadsheet_url || null,
    googleSpreadsheetError: body.google_spreadsheet_error || null,
  }
}];

const session = $json.data?.[0] || null;
if (!session?.id) {
  return [{ json: { ...$json, statusLookupError: 'Активного документа пока нет. Сначала отправьте файл.' } }];
}
if (!session.backend_upload_id) {
  if (session.status === 'collecting') {
    return [{ json: { ...$json, statusLookupError: 'Документ ещё не отправлен в backend. Нажмите «Продолжить» после последней страницы.' } }];
  }
  return [{ json: { ...$json, statusLookupError: 'Для этого чата backend-загрузка пока не найдена.' } }];
}
return [{ json: { ...$json, sessionRowId: session.id, backendUploadId: session.backend_upload_id, backendTraceId: session.backend_trace_id || '' } }];

function formatMoney(value) {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  if (!Number.isFinite(num)) return String(value);
  return num.toLocaleString('ru-RU', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
}
const source = $('Prepare Status Check').first().json;
const response = $json.body ? $json : { statusCode: 200, body: $json };
const body = response.body || {};
const statusCode = Number(response.statusCode || 200);
let replyText = 'Статус недоступен.';
if (statusCode >= 400) {
  const detail = body.detail;
  const errorText = typeof detail === 'string' ? detail : (detail?.error_message || body.message || `Backend вернул ошибку ${statusCode}.`);
  replyText = `Не удалось получить статус документа.\n${errorText}`;
} else if (!body.completed) {
  replyText = 'Документ ещё обрабатывается в backend.';
} else {
  const summary = body.document_summary || {};
  const lines = [];
  if (body.status === 'processing_error') {
    lines.push('Обработка завершилась ошибкой.');
    if (body.error_text) lines.push(body.error_text);
  } else {
    lines.push(body.message || 'Документ обработан.');
    if (summary.supplier) lines.push(`Поставщик: ${summary.supplier}`);
    if (summary.invoice_number) lines.push(`Накладная: ${summary.invoice_number}`);
    if (summary.total_sum !== null && summary.total_sum !== undefined) lines.push(`Сумма: ${formatMoney(summary.total_sum)}`);
    if (body.google_spreadsheet_url) {
      lines.push('');
      lines.push('Готовая таблица:');
      lines.push(body.google_spreadsheet_url);
    }
    if (body.google_spreadsheet_error) lines.push(`Предупреждение: ${body.google_spreadsheet_error}`);
  }
  replyText = lines.join('\n');
}
return [{ json: { ...source, replyText } }];
